exercises.solution:
def compare_signatures(sqisign: dict, dilithium: dict) -> dict:
    return {
        'size_winner': 'sqisign' if sqisign['sig_bytes'] < dilithium['sig_bytes'] else 'dilithium',
        'speed_winner': 'dilithium' if dilithium['sign_ms'] < sqisign['sign_ms'] else 'sqisign',
        'size_ratio': dilithium['sig_bytes'] / sqisign['sig_bytes'],
        'speed_ratio': sqisign['sign_ms'] / dilithium['sign_ms']
    }

def recommend_scheme(use_case: str) -> str:
    size_critical = ['embedded', 'iot', 'certificate', 'firmware']
    speed_critical = ['server', 'realtime', 'blockchain', 'api']

    if any(s in use_case.lower() for s in size_critical):
        return 'Consider SQIsign (smallest signatures)'
    elif any(s in use_case.lower() for s in speed_critical):
        return 'Use ML-DSA/Dilithium (fast operations)'
    return 'Default: ML-DSA/Dilithium (NIST standard)'

def bandwidth_comparison(n_signatures: int) -> dict:
    sqisign_sig = 177
    dilithium_sig = 2420
    sqisign_total = n_signatures * sqisign_sig
    dilithium_total = n_signatures * dilithium_sig
    return {
        'sqisign_bytes': sqisign_total,
        'dilithium_bytes': dilithium_total,
        'savings_bytes': dilithium_total - sqisign_total,
        'savings_percent': (1 - sqisign_total / dilithium_total) * 100
    }

def break_even_time(sqisign_ms: float, dilithium_ms: float, bandwidth_savings: int, bandwidth_cost_per_byte: float) -> float:
    time_cost = sqisign_ms - dilithium_ms
    bandwidth_benefit = bandwidth_savings * bandwidth_cost_per_byte
    return bandwidth_benefit / time_cost if time_cost > 0 else float('inf')

