def pqc_taxonomy() -> dict:
    return {
        'lattice': {
            'kem': ['ML-KEM/Kyber'],
            'sig': ['ML-DSA/Dilithium', 'Falcon']
        },
        'hash': {
            'sig': ['SLH-DSA/SPHINCS+']
        },
        'code': {
            'kem': ['Classic McEliece', 'BIKE', 'HQC']
        },
        'isogeny': {
            'kem': ['CSIDH'],
            'sig': ['SQIsign']
        }
    }

def is_standardized(scheme: str) -> bool:
    standardized = ['ML-KEM', 'Kyber', 'ML-DSA', 'Dilithium', 'SLH-DSA', 'SPHINCS+', 'Classic McEliece']
    return any(s.lower() in scheme.lower() for s in standardized)

