exercises.solution:
def evaluate_improvement(current_speed_ms: float, speedup_factor: float, target_ms: float) -> dict:
    improved_ms = current_speed_ms / speedup_factor
    meets_target = improved_ms <= target_ms
    needed_speedup = current_speed_ms / target_ms
    return {
        'improved_ms': improved_ms,
        'meets_target': meets_target,
        'needed_speedup': needed_speedup,
        'additional_needed': max(1, needed_speedup / speedup_factor)
    }

def research_priorities(constraints: dict) -> list:
    priorities = []
    if constraints.get('speed_critical'):
        priorities.append('Algorithm optimization')
        priorities.append('Hardware acceleration')
    if constraints.get('size_critical'):
        priorities.append('Compression techniques')
    if constraints.get('security_uncertain'):
        priorities.append('Cryptanalysis')
        priorities.append('Security proofs')
    priorities.append('Standardization efforts')
    return priorities
